import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            long N = fs.nextLong();
            long x1 = fs.nextLong();
            long y1 = fs.nextLong();
            long x2 = fs.nextLong();
            long y2 = fs.nextLong();
            if (x1 == x2 && y1 == y2) {
                sb.append(0).append('\n');
                continue;
            }
            boolean in1 = (x1 >= 1 && x1 <= N && y1 >= 1 && y1 <= N);
            boolean in2 = (x2 >= 1 && x2 <= N && y2 >= 1 && y2 <= N);
            int ans;
            if (in1 && in2) {
                long man = Math.abs(x1 - x2) + Math.abs(y1 - y2);
                ans = (man < 2) ? (int)man : 2;
            } else if (in1 || in2) {
                ans = 1;
            } else {
                ans = 0;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

